def solve(s):
    char_idx = {}
    max_len = start = 0
    for i, c in enumerate(s):
        if c in char_idx and char_idx[c] >= start:
            start = char_idx[c] + 1
        char_idx[c] = i
        max_len = max(max_len, i - start + 1)
    return max_len

